import{bQ as d,aL as r,u as e,G as a}from"./chunks/framework.D06dwy5q.js";const p=JSON.parse('{"title":"知识库简介","description":"","frontmatter":{"title":"知识库简介"},"headers":[],"relativePath":"知识库简介.md","filePath":"知识库简介.md","lastUpdated":null}'),o={name:"知识库简介.md"};function n(s,t,i,l,h,_){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="知识库简介" tabindex="-1">知识库简介 <a class="header-anchor" href="#知识库简介" aria-label="Permalink to &quot;知识库简介&quot;">​</a></h1><p>建这个知识库主要有两个原因：一是整理自己零散的知识，形成体系，边写边补，以后回看也方便查漏补缺；二是做知识分享，笔记放在网上，如果能顺便帮到别人，那就算意外之喜了。</p><p>这里的内容不是教程也不是权威指南，只是一个运维人的学习笔记，肯定有疏漏和错误，我会持续修正。</p><h2 id="知识库大纲" tabindex="-1">知识库大纲 <a class="header-anchor" href="#知识库大纲" aria-label="Permalink to &quot;知识库大纲&quot;">​</a></h2><table tabindex="0"><thead><tr><th>章节</th><th>内容</th></tr></thead><tbody><tr><td>00. 互联网与架构基础</td><td>网站访问、DNS、HTTP、前后端、数据库、集群、高可用和技术选型。</td></tr><tr><td>01. Linux 基础</td><td>目录、文件、权限、进程、磁盘、网络、日志、防火墙和初始化。</td></tr><tr><td>02. Shell 脚本</td><td>Bash 语法、文本处理、日志分析和常见运维脚本。</td></tr><tr><td>03. 远程运维</td><td>SSH、堡垒机、tmux、文件传输、rsync 和日常操作规范。</td></tr><tr><td>04. MySQL</td><td>SQL、索引、权限、备份恢复、故障排查、主从复制和高可用。</td></tr><tr><td>05. Redis</td><td>持久化、内存、主从、哨兵、Cluster、安全和日常运维。</td></tr><tr><td>06. Web 服务</td><td>Nginx、HTTPS、反向代理、Tomcat 和 Web 服务排错。</td></tr><tr><td>07. 服务注册与配置中心</td><td>Nacos 部署、服务发现、配置管理和平台操作。</td></tr><tr><td>08. 负载均衡与高可用</td><td>LVS、HAProxy、Keepalived 和常见高可用组合。</td></tr><tr><td>09. 容器化</td><td>Docker、镜像、网络、存储、Compose、containerd 和 Harbor。</td></tr><tr><td>10. Kubernetes</td><td>集群、工作负载、网络、存储、发布、安全、排错和生产基线。</td></tr><tr><td>11. 分布式存储</td><td>NFS、Ceph、MinIO 和云原生场景里的存储对接。</td></tr><tr><td>12. 可观测性与监控告警</td><td>Prometheus、Grafana、Alertmanager、Nightingale、Zabbix 和 K8s 监控。</td></tr><tr><td>13. 日志平台</td><td>日志采集、存储、检索和分析，施工中。</td></tr><tr><td>14. 链路追踪</td><td>Trace、Span、调用拓扑和性能定位，施工中。</td></tr><tr><td>15. CI/CD</td><td>流水线、制品、发布、回滚和持续交付，施工中。</td></tr><tr><td>16. 消息队列</td><td>Kafka、RabbitMQ、消费模型和积压排查，施工中。</td></tr><tr><td>17. 自动化运维</td><td>Ansible、Terraform、任务编排和 IaC，施工中。</td></tr><tr><td>18. Python 脚本</td><td>Python 基础、文件处理、系统交互、网络批量管理和小项目。</td></tr><tr><td>19. 轻量前端</td><td>HTML、CSS、JavaScript、DOM、请求、Vue 和页面练习。</td></tr><tr><td>20. Python 后端开发</td><td>FastAPI、数据库、认证权限、任务、Webhook、审计和平台实战。</td></tr><tr><td>21. Node.js</td><td>Node 运行时、npm、异步、文件路径、系统交互和 Express API。</td></tr><tr><td>22. Go 语言</td><td>Go 基础、并发、工程化、client-go、Operator、服务开发和部署。</td></tr></tbody></table>',5)])])}const b=d(o,[["render",n]]);export{p as __pageData,b as default};
